-- ── SignRequest ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cloud-based e-signature platform for sending, signing and managing legally binding documents, acquired by Box in 2021.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription (per user/month)$q$, pricing_model),
  starting_price = COALESCE($q$$9/month per user (Professional plan)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Amsterdam, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Dutch$q$]::text[],
  seo_title = COALESCE($q$SignRequest Review 2026: Pricing, Features and Box Integration$q$, seo_title),
  seo_meta_description = COALESCE($q$SignRequest is an e-signature platform now owned by Box. See pricing, features, pros and cons, and how it compares to SignNow, SignWell and DocuSign.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SignRequest is a cloud-based electronic signature platform that lets individuals and businesses send, sign, and manage legally binding documents online. The company was founded in Amsterdam, the Netherlands, in 2014 and built a reputation as a simple, affordable e-signature tool for small and mid-sized businesses before being acquired by Box, Inc. in February 2021 for an aggregate purchase price of 55 million US dollars. Since the acquisition, SignRequest has operated as a wholly owned subsidiary of Box and its e-signature technology has been integrated into Box Sign, Box's native e-signature product; Box has stated it is no longer building new API integrations under the SignRequest name and points developers toward the Box Sign API instead. SignRequest still offers standalone plans directly, including a free tier for occasional signers sending up to a handful of documents per month, and paid Professional and Business tiers priced per user per month that add templates, team management, bulk sending, and integrations with tools such as Google Drive, Dropbox, and Salesforce. Typical SignRequest users are freelancers, small businesses, and teams that need straightforward, legally compliant e-signatures (eIDAS and ESIGN Act compliant) without the cost or complexity of larger enterprise contract lifecycle management suites. Because Box now owns the technology, prospective buyers evaluating SignRequest today should also consider Box Sign as the actively developed successor product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fede56b3-f85c-4052-aeaf-1ba74f7f371f';

