-- ── SignWell ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Simple, affordable e-signature software (formerly Docsketch) for sending, signing and tracking legally binding documents.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription$q$, pricing_model),
  starting_price = COALESCE($q$$10/month (Light plan, monthly)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Portland, Oregon, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SignWell Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$SignWell (formerly Docsketch) is an affordable e-signature platform. Compare its Free, Light, Business and Enterprise plans, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SignWell is an electronic signature platform, formerly branded Docsketch, that helps individuals and businesses send, sign, and track legally binding documents online. The product launched under the Docsketch name in 2019 and rebranded to SignWell in 2021 as it expanded from a document-drafting tool into a full e-signature service; the company is headquartered in Portland, Oregon, United States. SignWell markets itself as a simpler, more affordable alternative to larger e-signature platforms like DocuSign and Adobe Sign, with a pricing structure built around a free tier and low monthly per-sender pricing rather than complex enterprise contracts. The Free plan supports one sender, one template, and up to three documents per month at no cost; the Light plan starts at 10 US dollars per month (or 12 US dollars per month billed monthly with an annual discount) and removes the document cap while adding template links, bulk sending, conditional fields, and data validation; the Business plan starts at 30 US dollars per month and adds custom branding, request attachments, and in-person signing for up to three senders; and an Enterprise plan offers custom pricing for large teams with unlimited templates and documents and dedicated support. SignWell also offers a standalone API with pay-as-you-go pricing, starting at 0.85 US dollars per document after 25 free API documents per month, decreasing at higher volume. All plans include unlimited document signers at no extra cost, audit trails, and tamper-proof document sealing, and there are no long-term contracts or cancellation fees on any plan.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '082213b2-ced8-444a-8548-3b973c136452';

