-- ── Silex ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, no-code website builder for creating static sites visually, maintained by the non-profit Silex Labs.$q$, short_description),
  pricing_model = COALESCE($q$Free / open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Silex Review 2026: Free Open-Source No-Code Website Builder$q$, seo_title),
  seo_meta_description = COALESCE($q$Silex is a free, open-source, no-code website builder for static sites. See features, hosting options, pros, cons and how it compares to Webflow.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Silex is a free and open-source, no-code website builder that lets designers and developers visually create static websites directly in the browser, positioned as an open alternative to proprietary builders like Webflow. The project traces back to 2003, created by Alex Hoyau along with Pol Goasdoue and Pierre Teissiere, and was substantially rebuilt from scratch in 2013 using JavaScript and Node.js to modernize the codebase. Silex is owned and maintained by Silex Labs, a French non-profit organization with no investors and no exit strategy, and it is a recognized project of OW2, the European open-source software community, having won the OW2 Best Project Award in the Technology category. Silex is licensed under the AGPL and is explicitly and permanently free: there are no paywalls, tiered feature restrictions, or premium-only functionality gating core use of the tool. Users can start building immediately in the hosted editor at v3.silex.me with nothing to install, or self-host the open-source server via Docker, Node.js, or a one-click deployment on CapRover for full control over their data and hosting. Silex supports drag-and-drop visual page building alongside direct HTML, CSS, and JavaScript editing for more advanced users, and it can pull dynamic content from external sources including WordPress, Strapi, Squidex, Supabase, or any GraphQL API, letting designers build headless, CMS-driven static sites without writing a backend. Optional paid services such as managed hosting or professional consulting are available from the community, but the core software itself remains free for everyone.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5b05cba9-d8b6-4cbf-8bf4-824461bac8ef';

