-- ── SilverBullet ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, self-hosted personal knowledge management app built on Markdown with an integrated Lua scripting environment.$q$, short_description),
  pricing_model = COALESCE($q$Free / open source (optional paid SilverBullet+ desktop edition)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SilverBullet Review 2026: Free Self-Hosted Notes App$q$, seo_title),
  seo_meta_description = COALESCE($q$SilverBullet is a free, open-source, self-hosted Markdown notes app with Lua scripting and wiki-style linking. See features, pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SilverBullet is a free, open-source, self-hosted personal knowledge management application built around plain Markdown files, created by developer Zef Hemel and first released in 2022. It is described by its creator as a programmable, private, browser-based personal knowledge platform, and it distributes as a single self-contained server binary or Docker container that users install on their own infrastructure, such as a home server, VPS, or Raspberry Pi. All notes, referred to as a 'Space,' are stored as plain Markdown files on disk, giving users full ownership and portability of their data with no proprietary file format or cloud dependency. SilverBullet combines a clean live-preview Markdown editor with wiki-style bidirectional linking between pages using double-bracket page links and linked mentions, a built-in structured database and query language for treating notes as queryable data, and a fully integrated Lua scripting environment that lets users write custom commands, page templates, and interactive widgets directly inside their notes. The application runs as a Progressive Web App, supporting both online, synced, and fully offline operation once installed. SilverBullet is licensed under the MIT license, making it free and open source with no cost for the core self-hosted application; a separate commercial offering called SilverBullet+ exists for users who want a packaged desktop edition, but the underlying open-source project remains free. It is best suited to technically comfortable users, developers, and privacy-conscious note-takers who prefer self-hosting and plain-text data ownership over hosted SaaS note apps like Notion or Obsidian Sync.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3c8191c2-eb3f-4d5e-8efc-4c1e054d313b';

