-- ── Silverstripe CMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source PHP content management system and framework from New Zealand, offering flexible content modeling and headless delivery.$q$, short_description),
  pricing_model = COALESCE($q$Free / open source (commercial support, hosting and development available)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2000, founded_year),
  company_size = COALESCE($q$~100 employees$q$, company_size),
  headquarters = COALESCE($q$Wellington, New Zealand$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Silverstripe CMS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Silverstripe CMS is an open-source PHP content management system from New Zealand. See features, pricing, pros, cons and top use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Silverstripe CMS is an open-source PHP content management system and framework originally founded as Totally Digital in Wellington, New Zealand, in February 2000 by Sam Minnee, Tim Copeland, and Sigurd Magnusson, all three of whom remain involved with the company today. The team built its first CMS version by 2003 and later open-sourced the platform, which significantly expanded its international adoption and use in large-scale government and enterprise projects. Silverstripe Ltd is a Wellington-based company with a team of around 100 developers, designers, and support staff, and it continues to lead ongoing development of the open-source Silverstripe CMS alongside a global open-source community. Notable organizations that have used Silverstripe CMS include Television New Zealand (TVNZ), the New Zealand Government, Whittaker's, Air New Zealand, and OpenStack. Silverstripe CMS is free and open source, distributed and maintained by the community, with no license fee to download, self-host, or modify the software; the Silverstripe company generates revenue through commercial support, hosting, and custom development services rather than software licensing. Technically, it combines a traditional content management system with an API-first, headless-capable architecture, allowing content to be delivered to websites as well as external applications. Core CMS features include flexible content blocks for page layout, granular user roles and permissions with approval workflows, version history with the ability to revert changes, and a large add-on and module ecosystem for extending functionality. Silverstripe is best suited to organizations, agencies, and government bodies that need a customizable, developer-friendly CMS without recurring software license costs, and that value having full source-code access and self-hosting control.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fbbf64a9-d7e7-4ac7-970d-5bf277603dba';

