  headquarters = COALESCE($q$Tel Aviv, Israel$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Similarweb Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Similarweb (NYSE: SMWB) is a digital intelligence platform for web traffic and market analytics. Compare pricing plans, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Similarweb is a publicly traded digital intelligence and web analytics platform, listed on the New York Stock Exchange under the ticker SMWB since its IPO in May 2021 at a roughly 1.6 billion US dollar valuation. The company was founded in 2007 and is headquartered in Tel Aviv, Israel, with additional offices across roughly 15 global locations and a workforce estimated between 1,000 and 5,000 employees. Similarweb's platform estimates website and app traffic, audience demographics, engagement metrics, referral and keyword data, and competitive benchmarking across more than 100 million websites and apps, serving over 10,000 paying customers spanning marketing, sales, investment research, and e-commerce teams. Pricing is structured across self-service and sales-quoted tiers: the self-service Starter plan starts around 125 US dollars per month when billed annually (or about 149 US dollars per month billed monthly), and a Professional self-service plan runs roughly 333 to 399 US dollars per month depending on billing cycle. Higher tiers such as Team and Business are sold through Similarweb's sales team with published estimates around 14,000 and 35,000 US dollars per year respectively for a handful of users and defined history and keyword limits, while Enterprise plans are fully custom, typically requiring a minimum of 10 users, offering the longest historical data window, unlimited keyword tracking, and API access, with real-world enterprise contract values commonly ranging from tens of thousands to over 100,000 US dollars annually depending on scope. Similarweb is commonly used by SEO teams, competitive intelligence analysts, investors, and e-commerce and marketing teams that need third-party estimates of a website's or app's traffic and audience rather than first-party analytics from tools like Google Analytics.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6ec8c9fb-dc39-4341-8a0f-b8c3e18a508d';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '6ec8c9fb-dc39-4341-8a0f-b8c3e18a508d' AND logo IS NULL AND website IS NOT NULL;

